const LIB = require('../lib/jibo-cai-utils');
const CancelToken = LIB.CancelToken;
const CancelTokenSession = LIB.CancelTokenSession;
const TimeUtils = LIB.TimeUtils;


describe('CancelTokenSession', () => {

	it('Handle regular timeout promise', (done) => {
		let session = new CancelTokenSession();
		session.wrap(TimeUtils.wait(10).then(() => 10))
			.then(data => {
				expect(session.size()).to.equal(0);
				expect(data).to.equal(10);
				done();
			}).catch(done);
		expect(session.size()).to.equal(1);
	});

	it('Paused timeout promise', (done) => {
		let session = new CancelTokenSession();
		let longWait = false;

		session.wrap(TimeUtils.wait(10).then(() => 10))
			.then(data => {
				expect(session.size()).to.equal(0);
				expect(data).to.equal(10);
				expect(longWait).to.equal(true);
				done();
			}).catch(done);
		expect(session.size()).to.equal(1);
		session.setPaused(true);

		TimeUtils.wait(30).then(() => {
			expect(session.size()).to.equal(1);
			longWait = true;
			session.setPaused(false);
		});
	});

	it('Paused error', (done) => {
		let session = new CancelTokenSession();
		let longWait = false;

		session.wrap(TimeUtils.wait(10).then(() => {
			throw 'Bla';
		})).catch((/*e*/) => {
			expect(session.size()).to.equal(0);
			expect(longWait).to.equal(true);
			done();
		}).catch(done);

		expect(session.size()).to.equal(1);
		session.setPaused(true);

		TimeUtils.wait(30).then(() => {
			expect(session.size()).to.equal(1);
			longWait = true;
			session.setPaused(false);
		});
	});

	it('Wait for all outstanding', (done) => {
		let session = new CancelTokenSession();
		let longWait = false;
		let arr = [];
		session.wrap(TimeUtils.wait(10).then(() => arr.push(1)));
		session.wrap(TimeUtils.wait(20).then(() => {
			throw 'Bla';
		}));
		session.wrap(TimeUtils.wait(30).then(() => arr.push(3)));
		expect(session.size()).to.equal(3);
		session.setPaused(true);

		TimeUtils.wait(50).then(() => {
			expect(session.size()).to.equal(3);
			longWait = true;
			session.setPaused(false);
		});

		session.waitForAll().then(() => {
			expect(session.size()).to.equal(0);
			expect(arr).to.deep.equal([1,3]);
			expect(longWait).to.equal(true); // Because this gets resolved when the actual promises resolve
			done();
		}).catch(done);
	});

	it('Canceling tokens in session (rejecting waitForAll immediately)', (done) => {
		let session = new CancelTokenSession();
		let arr = [];
		session.wrap(TimeUtils.wait(10).then(() => arr.push(1)));
		session.wrap(TimeUtils.wait(30).then(() => arr.push(2)));
		expect(session.size()).to.equal(2);
		session.waitForAll()
			.catch(err => {
				expect(arr.length).to.equal(0);
				expect(err.message).to.equal('Promise session canceled');
				done();
			});

		session.cancel();
	});

	it('Canceling tokens in session (rejecting waitForAll when cancel finished)', (done) => {
		let session = new CancelTokenSession();
		let arr = [];
		session.wrap(TimeUtils.wait(10).then(() => arr.push(1)));
		session.wrap(TimeUtils.wait(30).then(() => arr.push(2)));
		expect(session.size()).to.equal(2);
		session.waitForAll(false)
			.catch(err => {
				expect(arr.length).to.equal(2);
				expect(err.message).to.equal('Promise session canceled');
				done();
			});

		session.cancel();
	});

	it('Waiting for canceled tokens', (done) => {
		let session = new CancelTokenSession();
		let arr = [];

		// The inside promise adds 1 to array when done
		// The cancel token promise adds 2 to the array when done
		const internal = TimeUtils.wait(10).then(() => arr.push(1));
		session.wrap(internal).then(() => arr.push(2));

		expect(session.size()).to.equal(1);

		session.cancel().then(() => {
			session
			expect(arr).to.deep.equal([1]);
			done();
		});
	});

	it('Adding token while waiting for canceled session', () => {
		let session = new CancelTokenSession();
		session.wrap(TimeUtils.wait(10));
		expect(session.size()).to.equal(1);

		session.cancel();
		expect(() => {
			session.wrap(TimeUtils.wait(10));
		}).to.throw;
	});

	it('onFailed gets called', (done) => {
		let token = new CancelToken(TimeUtils.wait(10), () => done());
		token.cancel();
	});

});
